sys_ui_action.script:
// Copyrights belong to Discover Technologies LLC. © 2019 Discover Technologies LLC
// Script Continued Below
// STRY0105845 - DIA- Draft Scheduled Tasks- Create Draft Task State

publishTask();

// Use this function to run reopen tasks step
function publishTask() {
    new Task_uiAction().uiAction_PublishDraftTasks(current, 'taskOnly');

	// Redirect platform to stay on this task
	if (typeof spModal == 'undefined' ) {
		action.setRedirectURL(current);
	}
	// DFCT0010781 moved the info message out of this method and into the ui action so it isn't called for all sub tasks
	gs.addInfoMessage(current.task_name + gs.getMessage('Tasker - has been Published'));

}
